var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"사진, 사진, 사진......! 어디 있니, 사진아......!","JPN":"写真、写真、写真……！　写真はどこ……？","ENG":"Photo, photo, photo... Where is the photo?","TWN":"照片，照片，照片……！在哪呢，照片……！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으와앙!?","JPN":"うわっ！？","ENG":"Eeeek?!","TWN":"哦哇啊！？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이, 거기 처박혀서 뭐 해!","JPN":"ガキ、そこで何をしている！","ENG":"What are you doing in there, kid!","TWN":"小鬼，你在那裡幹什麼！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"죄, 죄송해요!","JPN":"ご、ごめんなさい！","ENG":"S-sorry!","TWN":"對、對不起！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗?! 사진이다!","JPN":"あっ！　あった！","ENG":"Oh! There it is!","TWN":"啊？！是照片！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니! 사진 찾았어요!","JPN":"リタお姉ちゃん！　写真を見つけました！","ENG":"Rita! I found the photo!","TWN":"麗塔姐姐！我找到照片了！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"자랑할 시간 없어! 당장 찢어 버려!","JPN":"いちいち報告しなくていいから！　今すぐ破れ！","ENG":"We don't have time for show and tell! Just destroy it now!","TWN":"別炫耀了！快撕了它！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"아......","JPN":"あ……","ENG":"Ah...","TWN":"啊……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L15_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"추워...... 언, 니......","JPN":"寒いよ……お姉ちゃん……","ENG":"It's cold... Sis...","TWN":"好冷……姐、姐姐……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"이제, 그만...... 집으로......","JPN":"もう……家に……","ENG":"Let's... go home...","TWN":"現在，要……回家……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"침식파 반응 소멸. 유사 데몬 타입 침식체의 격퇴에 성공했습니다.","JPN":"侵食波反応消滅。疑似デーモンタイプの侵食体の撃退に成功しました。","ENG":"Corruption Ray response no longer detected. The quasi demon-type C.O. has been defeated.","TWN":"侵蝕波反應消失。成功擊退類似惡魔型侵蝕體。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"정말요?! 저희가 이겼어요?!","JPN":"本当！？　私たちの勝ちですか？","ENG":"Really?! Did we really win?!","TWN":"真的嗎？！我們贏了？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"쳇...... 시답잖은 일로 힘을 너무 낭비했어.","JPN":"ちっ……くだらんことで力を無駄に使いすぎた。","ENG":"Hmpf... I wasted too much energy on that stupid thing.","TWN":"切……為一點小事浪費太多力氣了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니! 고생 많았어요! 언니 덕분에 ","JPN":"リタお姉ちゃん！　お疲れ様でした！　おかげで……","ENG":"Rita! Great work! Thanks to you— ","TWN":"麗塔姐姐！辛苦了！多虧了姐姐呢！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으브븝!","JPN":"うううっ！","ENG":"Mmph!","TWN":"呃啊！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_07"},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너, 팔에 그 상처는 뭐야? 언제 생겼어?","JPN":"おい、お前その腕の傷はなんだ？　いつやった？","ENG":"What's that scratch on your arm? When did you get hurt?","TWN":"你，手臂上的傷是怎麼回事？什麼時候受傷的？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"흐, 흐헤 엉히 오히 엉에 아흐러다(그, 그게 언니 오기 전에 막으려다)......","JPN":"んぐっ、ぐう、うぐぐぐぐっ(リ、リタお姉ちゃんが来る前に止めようとして)……","ENG":"Hwell, hi hwas hying who thtof pher wephor hyu ghof phere... (Well, I was trying to stop her before you got here...)","TWN":"呃，呃啊，嗯嗯，呃（是、是在姐姐來之前為了阻止她）……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"볼수록 굉장하네, 저 여자. 혼자서 그림자를 쓰러트리다니......","JPN":"すごいな、あの女。一人でシャドウを倒すなんて……","ENG":"She really is something else, isn't she? Defeating a Shadow all by herself...","TWN":"真是越看越厲害，那個女人。竟然一個人打倒了暗影……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"지금 그게 대수입니까? 어서 이 근처를 샅샅이 뒤지세요!","JPN":"今はそんなことどうだっていいです！　はやく周辺を捜索してください！","ENG":"Who cares about that? Search the entire area at once!","TWN":"那個重要嗎？快去好好搜一下這附近！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"아니, 이미 쑥대밭이 됐는데 뭐하러요?","JPN":"いや、こんなにめちゃくちゃになった場所で何を？","ENG":"What for? This place is in shambles!","TWN":"我說，這裡已經成了一片廢墟了，搜什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그걸 질문이라고 해요? 어서 그 카메라를 찾아야죠!","JPN":"はあ？　カメラを探すに決まっているじゃないですか！","ENG":"What kind of a question is that? We've got to find that camera!","TWN":"這還用問嗎？當然要找到那個相機了！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"카메라를요? 그런 잡동사니를 뭐하러......?","JPN":"カメラを？　あんながらくたをなぜ……？","ENG":"The camera? What would you need that junk for?","TWN":"相機？為什麼還要找那個垃圾……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"저처럼 배운 사람은 다르거든요. 뭐든 연구와 조사를 통해 올바른 쓰임새를 찾아낼 수 있어요.","JPN":"僕みたいに学んだ者にはわかるんです。すべては研究と調査によって正しい使い方を見つけられるのです。","ENG":"A learned man like me can find a use for that. With enough research and study, anything can be useful.","TWN":"像我這樣有學問的人跟你們不一樣。不管是什麼，通過研究和調查都能找到正確的用途。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"제 예상이 맞다면, 그 카메라는 찍힌 사람의 미래를 현실에 투영해 주는 유물이 확실합니다.","JPN":"僕の予想が正しければ、そのカメラは被写体の未来を現実に投影してくれる遺物に間違いありません。","ENG":"If my conjecture is correct, this must be an Artifact that projects the future of the photographed subject.","TWN":"如果我的猜測沒錯，那個相機就是能把所拍之人的未來投射到現實中的遺物。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"미래를 알 수 있다니! 얼마나 큰 가치가 있을지 상상해 보세요!","JPN":"未来がわかるなんて！　どれほど価値のある品物か想像できますか？","ENG":"If we can foresee the future... Imagine how valuable that would be!","TWN":"能預知未來呢！你好好想想，這是多麼大的價值啊！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"어, 그게...... 선생님, 말 좀 가려 하는 게......","JPN":"えっと……先生。その話はちょっと……","ENG":"Oh, err... Maybe you should choose your words more carefully, Doc...","TWN":"呃，這……先生，您說的會不會太誇張……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"어윽!? 컥! 수, 숨이......!","JPN":"くっ！　ぐはっ！　い、息が……！","ENG":"Ack! Ngh! I-I can't breathe...","TWN":"呃咳！？呃！呼，呼吸……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT"},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"어, 언니!","JPN":"リ、リタお姉ちゃん！","ENG":"R-Rita!","TWN":"呃，姐姐！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이 넌 조용히 있어.","JPN":"ガキはだまってろ。","ENG":"Keep your mouth shut, kid.","TWN":"小鬼你給我老實待著。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"기회를 준 걸 원수로 갚다니 섭섭하군.","JPN":"お前さ、チャンスを与えてやったのに仇で返すなんてひどいじゃないか。","ENG":"So this is how you repay me for giving you another chance.","TWN":"我給你機會，你卻恩將仇報。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"다시 지껄여 봐, 윌버. 찍힌 사람의 뭘 어째?","JPN":"もう一回ほざいてみろ、ウィルバー。撮られた人の何がどうだって？","ENG":"What was all that hogwash you were spewing, Wilbur? Projects what now?","TWN":"你再說一次試試，韋爾伯。被拍到的人會怎樣？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이, 이거, 멱살부터, 놓고 말하는 게......","JPN":"こ、こんな乱暴はや、やめ……","ENG":"C-can you let go of me first...","TWN":"這、這個，你先放、放開我……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":" 케헥......!","JPN":"ぐはっ……！","ENG":" Ack!","TWN":" 呃咳……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_BONE_CRACK_02"},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"잘 들어. <color=#ffd34c>저건</color> 내 소유물이야.","JPN":"よく聞け。<color=#ffd34c>アレ</color>は私の所有物だ。","ENG":"Listen closely. <color=#ffd34c>That</color> is my property.","TWN":"聽著，<color=#ffd34c>她</color>是我的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저건, 너 같이 염치 없는 놈 때문에 상해도 될 물건이 아니라고.","JPN":"あれは、お前みたいな恥知らずのせいで傷ついていいものではない。","ENG":"It's not for some ingrate like you to do with as you please.","TWN":"她不是你這種不知廉恥的東西能傷害的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"한 번 더 그딴 소리 지껄여 봐. 프론트 베이고 뭐고 여기다 파묻어 버리겠어.","JPN":"また戯言をぬかしてみろ。フロントベイではなくここに生き埋めにしてやるからな。","ENG":"So try running that mouth of yours again. You can forget about Front Bay. I'll bury you right here.","TWN":"如果你膽敢再說那些沒用的。你也不必去前灣了，我直接把你埋在這裡。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아...... 알았으니까...... 목이...... 부, 부러지겠......","JPN":"わ、わかったから……首が……お、折れてしま……","ENG":"I... I got it... Please... Y-you'll break my neck...","TWN":"啊……知道了……脖、脖子……快斷了……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"쿨럭! 커헉, 헉! 케헥......!","JPN":"ガハッ！　ゲホゲホ……！","ENG":"*Cough!* *Cough, cough!* *Pant*","TWN":"咳咳！咳咳，呃！咳咳咳……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"지금부터 내 말 잘 들어.","JPN":"……今から私が言うことをよく聞け。","ENG":"Listen closely to what I'm saying.","TWN":"聽好了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"아, 네! 말씀해 주십시오!","JPN":"あ、はい！　なんなりと！","ENG":"Oh, right! I'm listening!","TWN":"啊，是！您請講！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내 소유물에 흠집 낸 배상은 확실하게 정산해야겠어.","JPN":"私の所有物に傷がついた分はしっかり賠償してもらうつもりだ。","ENG":"I'm going to have to charge this fool for damaging my property.","TWN":"我所有物產、抵押品…如果出現瑕疵的賠償，我必須算清楚。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 층에 있던 침식체들은 모두 처리했으니까 돈 될 만한 건 알아서 수거해.","JPN":"この付近の侵食体は全て処理したから、金になりそうなものはすべて回収しろ。","ENG":"I've already gotten rid of all the C.O.s on this floor. Collect everything worth money here.","TWN":"這一層的侵蝕體都處理完了，值錢的東西全部收過來。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"약속대로 이터니움은 물론이고, 아티팩트도 전부 우리 사무소에서 접수한다.","JPN":"約束どおりエタニウムはもちろん、アーティファクトもうちの事務所が引き取る。","ENG":"In addition to the Eternium as promised, Horizon Finance will also take all the Artifacts.","TWN":"按照約定，不僅是永恆之金，人造神器也全部由我們事務所接收。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너희 보수도 예외는 아냐, 풋내기들.","JPN":"お前らの報酬も例外じゃない。","ENG":"That includes your cut, you twits.","TWN":"你們的報酬也不例外，菜鳥們。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌을 붙여 두겠어. 물건에 함부로 손대면 방아쇠는 새끼손가락으로 당기게 될 거야.","JPN":"ホライズンをつけておく。戦利品に手を出したら、この先引き金を引く指は小指になるから覚悟しとけ。","ENG":"I'm going to have Horizon monitor you. If you take anything for yourselves, you'll be pulling triggers with your pinkies.","TWN":"全都會貼上地平線金融的LOGO標誌。如果有誰敢亂動東西，小心我砍了你們的手。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"절대 안 건드리죠! 죽을 뻔했다가 살아나서 다들 잔뜩 겁이 나 있는데요, 뭘!","JPN":"絶対に触れません！　死にそうになったところで助けられて、皆かなり怖がっているんです！","ENG":"Oh, we won't touch them! Everyone's scared out of their minds, having barely survived all that!","TWN":"絕對不會亂動的！我們好不容易死裡逃生，不會找死的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"따라 와, 꼬맹이.","JPN":"着いてこい、ガキ。","ENG":"Come along, kid.","TWN":"跟我來，小鬼。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이, 내 말 안 들려?","JPN":"ガキ、聞こえなかったか？","ENG":"Didn't you hear me, kid?","TWN":"小鬼，你沒聽到我說話嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 그게...... 갈게요!","JPN":"あ、はい……今行きます！","ENG":"Oh, well... I'm coming!","TWN":"啊，那個……這就來！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......언니.","JPN":"……リタお姉ちゃん。","ENG":"... Rita.","TWN":"……姐姐。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};